import { jsxs, jsx } from 'react/jsx-runtime';
import { Skeleton } from '../Skeleton/Skeleton.js';
import { classNames } from '../../helpers/classnames.js';

/**
 * Компонент для отображения состояния загрузки элемента навигации
 * Показывает кружок (иконка) и линию (текст) справа от него
 */
const NavigationItemSkeleton = ({ className, isChild = false, animated = true, }) => {
    return (jsxs("div", { className: classNames('navigation-item-skeleton', {
            'navigation-item-skeleton--child': isChild,
        }, className), children: [jsx(Skeleton, { variant: "circle", width: 24, height: 24, animated: animated, className: "navigation-item-skeleton__icon" }), jsx(Skeleton, { variant: "line", height: 24, width: "60%", animated: animated, className: "navigation-item-skeleton__text" })] }));
};

export { NavigationItemSkeleton };
